// Validate secret token header and sender chat_id
const headers = $input.first().json.headers || {};
const secretHeader = headers['x-telegram-bot-api-secret-token'] || '';
const expectedSecret = $env.TELEGRAM_WEBHOOK_SECRET || '';
if (secretHeader !== expectedSecret) {
  return [{json: {valid: false, reason: 'invalid_secret'}}];
}
const body = $input.first().json.body || {};
const chatId = body.message?.chat?.id?.toString() || body.callback_query?.message?.chat?.id?.toString() || '';
const expectedChatId = $env.TELEGRAM_CHAT_ID || '';
if (chatId !== expectedChatId) {
  return [{json: {valid: false, reason: 'unknown_sender'}}];
}
return [{json: {valid: true, body}}];

const body = $input.first().json.body || {};
const isCallbackQuery = !!body.callback_query;
const isMessage = !!body.message;
if (isCallbackQuery) {
  return [{json: {
    route: 'callback_query',
    callback_query_id: body.callback_query.id,
    callback_data: body.callback_query.data,
    message_id: body.callback_query.message?.message_id,
    chat_id: body.callback_query.message?.chat?.id
  }}];
}
if (isMessage) {
  const text = body.message.text || '';
  // Queue commands
  if (text === '/lista' || text.startsWith('/lista ')) {
    return [{json: {route: 'queue', queue_action: 'list', text}}];
  }
  if (text === '/saltados') {
    return [{json: {route: 'queue', queue_action: 'skipped', text}}];
  }
  if (/^\/a[ñn]adir?\s+/i.test(text) || text.startsWith('/add ')) {
    const title = text.replace(/^\/a[ñn]adir?\s+|^\/add\s+/i, '').trim();
    return [{json: {route: 'queue', queue_action: 'add', queue_title: title, text}}];
  }
  // Podcast commands
  if (text === '/podcasts') {
    return [{json: {route: 'podcasts', podcasts_action: 'list', text}}];
  }
  if (text.startsWith('/follow ')) {
    const raw = text.replace('/follow ', '').trim();
    const queries = raw.split(/[,\n]+/).map(s => s.trim()).filter(Boolean);
    if (queries.length > 1) {
      return [{json: {route: 'podcasts', podcasts_action: 'follow_multi', queries, text}}];
    }
    return [{json: {route: 'podcasts', podcasts_action: 'follow', query: queries[0] || raw, text}}];
  }
  if (text.startsWith('/unfollow ')) {
    const query = text.replace('/unfollow ', '').trim();
    return [{json: {route: 'podcasts', podcasts_action: 'unfollow', query, text}}];
  }
  if (/^\/rename\s/.test(text)) {
    const rest = text.replace(/^\/rename\s+/, '').trim();
    const spaceIdx = rest.search(/\s/);
    if (spaceIdx > 0) {
      const first = rest.slice(0, spaceIdx);
      const new_name = rest.slice(spaceIdx + 1).trim();
      const podcast_idx = parseInt(first, 10);
      if (!isNaN(podcast_idx) && new_name) {
        return [{json: {route: 'podcasts', podcasts_action: 'rename', podcast_idx: podcast_idx - 1, new_name, text}}];
      }
    }
    return [{json: {route: 'podcasts', podcasts_action: 'rename_help', text}}];
  }
  if (text === '/ayuda' || text === '/help') {
    return [{json: {route: 'podcasts', podcasts_action: 'help', text}}];
  }
  // Episode browse commands
  if (/^\/[uú]ltimos?\s/.test(text)) {
    const parts = text.replace(/^\/[uú]ltimos?\s+/, '').trim().split(/\s+/);
    const n = parseInt(parts[0], 10);
    const episode_count = isNaN(n) ? 3 : n;
    const podcast_filter = isNaN(n) ? parts.join(' ') : parts.slice(1).join(' ');
    return [{json: {route: 'episodes', episodes_action: 'bulk_add', episode_count, podcast_filter, text}}];
  }
  if (/^\/elegir\s/.test(text)) {
    const parts = text.replace(/^\/elegir\s+/, '').trim().split(/\s+/);
    const n = parseInt(parts[0], 10);
    const episode_count = isNaN(n) ? 5 : n;
    const podcast_filter = isNaN(n) ? parts.join(' ') : parts.slice(1).join(' ');
    return [{json: {route: 'episodes', episodes_action: 'browse', episode_count, podcast_filter, text}}];
  }
  if (/^\/desde\s/.test(text)) {
    return [{json: {route: 'episodes', episodes_action: 'browse_range', episode_count: 50, podcast_filter: '', raw_text: text, text}}];
  }
  if (/^\/recomienda/.test(text)) {
    const n = parseInt((text.split(/\s+/)[1] || ''), 10);
    return [{json: {route: 'recommend', recommend_count: isNaN(n) || n < 1 ? 3 : Math.min(n, 10), text}}];
  }
  if (text === '/perfil' || text === '/gustos') {
    return [{json: {route: 'profile', text}}];
  }
  if (/^\/prioridad\s/.test(text)) {
    const parts = text.replace(/^\/prioridad\s+/, '').trim().split(/\s+/);
    const podcast_idx = parseInt(parts[0], 10);
    const priority = parseFloat(parts[1]);
    if (!isNaN(podcast_idx) && !isNaN(priority)) {
      return [{json: {route: 'podcasts', podcasts_action: 'set_priority', podcast_idx: podcast_idx - 1, priority: Math.max(1, Math.min(10, priority)), text}}];
    }
    return [{json: {route: 'podcasts', podcasts_action: 'priority_help', text}}];
  }
  if (/^\/escuchado\s/i.test(text)) {
    const rest = text.replace(/^\/escuchado\s+/i, '').trim();
    const parts = rest.split(/\s*[·•|]\s*/);
    const title = parts[0].trim();
    const podcast = parts[1] ? parts[1].trim() : '';
    return [{json: {route: 'queue', queue_action: 'log_listened', queue_title: title, queue_podcast: podcast, text}}];
  }
  return [{json: {
    route: 'message',
    text,
    chat_id: body.message.chat?.id,
    message_id: body.message.message_id
  }}];
}
return [{json: {route: 'unknown'}}];

const data = $input.first().json.callback_data || '';
const parts = data.split(':');
const action = parts[0];
const inp = $input.first().json;

// Queue callback: q_add:{item_id} | q_done:{id} | q_skip:{id} | q_del:{id} | q_rate:{id}:{0-5}
if (action.startsWith('q_')) {
  return [{json: {
    action,
    item_id: parts[1] || '',
    queue_rating: parts[2] !== undefined ? parseInt(parts[2], 10) : null,
    callback_query_id: inp.callback_query_id,
    message_id: inp.message_id,
    chat_id: inp.chat_id,
    is_queue: true,
    is_podcasts: false
  }}];
}

// Podcasts callbacks: p_del:{index}, pf_choose:{id}, pf_none
if (action.startsWith('p_') || action.startsWith('pf_')) {
  return [{json: {
    action,
    item_id: parts[1] || '',
    callback_query_id: inp.callback_query_id,
    message_id: inp.message_id,
    chat_id: inp.chat_id,
    is_queue: false,
    is_podcasts: true
  }}];
}

// Episode browse skip callback
if (action === 'eb_skip') {
  return [{json: {
    action: 'eb_skip', item_id: parts[1] || '',
    callback_query_id: inp.callback_query_id,
    message_id: inp.message_id, chat_id: inp.chat_id,
    is_queue: true, is_podcasts: false
  }}];
}

// Standard: {action}:{type}:{item_id}
if (parts.length < 3) return [{json: {action: 'unknown', item_type: 'unknown', item_id: 'unknown', original: data, callback_query_id: inp.callback_query_id, message_id: inp.message_id, chat_id: inp.chat_id, is_queue: false, is_podcasts: false}}];
const [act, item_type, ...idParts] = parts;
return [{json: {
  action: act,
  item_type,
  item_id: idParts.join(':'),
  callback_query_id: inp.callback_query_id,
  message_id: inp.message_id,
  chat_id: inp.chat_id,
  is_queue: false,
  is_podcasts: false
}}];

const fs = require('fs');
const {action, item_type, item_id} = $input.first().json;
const ratingsPath = '/data/ratings_history.json';
const profilePath = '/data/user_profile.json';
const ratings = JSON.parse(fs.readFileSync(ratingsPath, 'utf8'));
const profile = JSON.parse(fs.readFileSync(profilePath, 'utf8'));
const isLike = action === 'like';
// Store quick rating
ratings.ratings.push({
  item_id,
  item_type,
  action,
  timestamp: new Date().toISOString()
});
fs.writeFileSync(ratingsPath, JSON.stringify(ratings, null, 2));
// Update profile scores
const delta = isLike ? 0.5 : -0.5;
const topicDelta = isLike ? 0.2 : -0.1;
if (item_type === 'podcast') {
  const podcast = profile.known_podcasts.find(p => p.id === item_id || p.rss_url?.includes(item_id));
  if (podcast) {
    podcast.feedback.quick_likes = (podcast.feedback.quick_likes || 0) + (isLike ? 1 : 0);
    podcast.feedback.quick_dislikes = (podcast.feedback.quick_dislikes || 0) + (!isLike ? 1 : 0);
  }
}
profile.profile_update_count = (profile.profile_update_count || 0) + 1;
profile.last_updated = new Date().toISOString();
fs.writeFileSync(profilePath, JSON.stringify(profile, null, 2));
const replyText = isLike ? '👍 Anotado.' : '👎 Anotado. Lo tendré en cuenta.';
return [{json: {reply_text: replyText, callback_query_id: $input.first().json.callback_query_id}}];

const {item_id, item_type, callback_query_id} = $input.first().json;
// Build rating request message
const ratingMsg = `⭐ *Puntúa este contenido*\n\nTema:\n[1] [2] [3] [4] [5]\n\nPresentador/Canal:\n[1] [2] [3] [4] [5]\n\n¿Lo recomendarías?\n[Sí] [No]`;
const inlineKeyboard = {
  inline_keyboard: [
    [{text:'1',callback_data:`topic_score:${item_type}:${item_id}:1`},{text:'2',callback_data:`topic_score:${item_type}:${item_id}:2`},{text:'3',callback_data:`topic_score:${item_type}:${item_id}:3`},{text:'4',callback_data:`topic_score:${item_type}:${item_id}:4`},{text:'5',callback_data:`topic_score:${item_type}:${item_id}:5`}],
    [{text:'Host 1',callback_data:`host_score:${item_type}:${item_id}:1`},{text:'Host 2',callback_data:`host_score:${item_type}:${item_id}:2`},{text:'Host 3',callback_data:`host_score:${item_type}:${item_id}:3`},{text:'Host 4',callback_data:`host_score:${item_type}:${item_id}:4`},{text:'Host 5',callback_data:`host_score:${item_type}:${item_id}:5`}],
    [{text:'👍 Lo recomendaría',callback_data:`recommend:${item_type}:${item_id}:yes`},{text:'👎 No',callback_data:`recommend:${item_type}:${item_id}:no`}]
  ]
};
return [{json: {rating_text: ratingMsg, inline_keyboard: JSON.stringify(inlineKeyboard), callback_query_id}}];

const fs = require('fs');
const profile = JSON.parse(fs.readFileSync('/data/user_profile.json', 'utf8'));
const ratingsHistory = JSON.parse(fs.readFileSync('/data/ratings_history.json', 'utf8'));
let lastDigest = {items: []};
try { lastDigest = JSON.parse(fs.readFileSync('/data/last_digest.json', 'utf8')); } catch(e) {}
let conversationSystemPrompt = '';
try { conversationSystemPrompt = fs.readFileSync('/prompts/conversation_system.md', 'utf8'); } catch(e) {
  try { conversationSystemPrompt = fs.readFileSync('/data/prompts/conversation_system.md', 'utf8'); } catch(e2) {
    conversationSystemPrompt = 'Eres un curador de contenidos personal. Gestiona reportes proactivos, cambios de preferencia y preguntas. Responde en español directo. Si hay profile_update, inclúyelo como JSON al final en bloque "profile_update": {}.';
  }
}
const detectIntentPayload = {
  model: "claude-sonnet-4-5",
  max_tokens: 256,
  system: "Clasifica el mensaje del usuario en uno de estos tipos: reporte_proactivo, cambio_preferencia, pregunta, otro. Responde SOLO con JSON puro sin markdown: {\"intent\": \"tipo\", \"confidence\": 0.9, \"extracted\": {}}",
  messages: [{role: "user", content: $input.first().json.text}]
};
return [{json: {
  text: $input.first().json.text,
  profile,
  ratingsHistory,
  lastDigest,
  conversationSystemPrompt,
  detectIntentPayload
}}];

const intentResponse = $input.first().json;
const content = intentResponse.content?.[0]?.text || '{}';
let intent;
try {
  // Try 1: direct parse
  intent = JSON.parse(content);
} catch(e1) {
  try {
    // Try 2: extract from ```json ... ``` block
    const mdMatch = content.match(/```(?:json)?\s*([\s\S]*?)```/);
    if (mdMatch) { intent = JSON.parse(mdMatch[1].trim()); }
    else throw new Error('no md block');
  } catch(e2) {
    try {
      // Try 3: extract first complete {...} using stack
      let depth = 0, start = -1, end = -1;
      for (let i = 0; i < content.length; i++) {
        if (content[i] === '{') { if (depth === 0) start = i; depth++; }
        else if (content[i] === '}') { depth--; if (depth === 0) { end = i; break; } }
      }
      if (start !== -1 && end !== -1) intent = JSON.parse(content.slice(start, end + 1));
      else throw new Error('no json found');
    } catch(e3) {
      intent = {intent: 'otro', confidence: 0.5, extracted: {}};
    }
  }
}

const ctx = $('Read Context').first().json;
const conversationPayload = {
  model: "claude-sonnet-4-5",
  max_tokens: 1024,
  system: ctx.conversationSystemPrompt || "Eres un curador de contenidos personal. Gestiona reportes proactivos, cambios de preferencia y preguntas. Responde en español directo. Si hay profile_update, inclúyelo como JSON al final en bloque \"profile_update\": {}.",
  messages: [{role: "user", content:
    "Mensaje: " + ctx.text +
    "\nIntención detectada: " + intent.intent +
    "\nPerfil: " + JSON.stringify(ctx.profile) +
    "\nÚltimo digest (primeros 5 items): " + JSON.stringify((ctx.lastDigest && ctx.lastDigest.items || []).slice(0,5)) +
    "\nHistorial de valoraciones: " + JSON.stringify((ctx.ratingsHistory && ctx.ratingsHistory.ratings || []).slice(-10)) +
    "\nReportes proactivos previos: " + JSON.stringify((ctx.ratingsHistory && ctx.ratingsHistory.proactive_reports || []).slice(-5))
  }]
};

return [{json: {
  intent: intent.intent,
  confidence: intent.confidence,
  extracted: intent.extracted || {},
  text: ctx.text,
  profile: ctx.profile,
  ratingsHistory: ctx.ratingsHistory,
  lastDigest: ctx.lastDigest,
  conversationPayload
}}];

const fs = require('fs');
const claudeResponse = $input.first().json;
const fullText = claudeResponse.content?.[0]?.text || '';
// Extract profile_update block if present
let profileUpdate = null;
const match = fullText.match(/"profile_update"\s*:\s*(\{[\s\S]*?\})/);
if (match) {
  try { profileUpdate = JSON.parse(match[1]); } catch(e) {}
}
// Clean reply (remove JSON block from user-facing text)
const replyText = fullText.replace(/```json[\s\S]*?```/g, '').replace(/"profile_update"\s*:\s*\{[\s\S]*?\}/g, '').trim();
// Apply profile update if present
if (profileUpdate) {
  const profilePath = '/data/user_profile.json';
  const profile = JSON.parse(fs.readFileSync(profilePath, 'utf8'));
  const {action, data} = profileUpdate;
  if (action === 'update_interest' && data?.topic && data?.weight_delta) {
    const current = profile.interests[data.topic] || 5;
    profile.interests[data.topic] = Math.max(1, Math.min(10, current + data.weight_delta));
  }
  if (action === 'add_host_affinity' && data?.host && data?.host_delta) {
    const current = profile.host_affinities[data.host] || 5;
    profile.host_affinities[data.host] = Math.max(1, Math.min(10, current + data.host_delta));
  }
  if (action === 'add_podcast' && data?.name) {
    const exists = profile.known_podcasts.find(p => p.name === data.name);
    if (!exists) {
      profile.known_podcasts.push({
        name: data.name,
        rss_url: data.rss_url || null,
        language: data.language || 'es',
        priority: 6,
        max_duration_minutes: 90,
        feedback: {topic_score: null, host_score: null, completion_rate: null, why_i_like: [], episodes_rated: 0, quick_likes: 0, quick_dislikes: 0}
      });
    }
  }
  if (action === 'update_podcast' && data?.name) {
    const podcast = profile.known_podcasts.find(p => p.name.toLowerCase() === data.name.toLowerCase());
    if (podcast) {
      if (data.topic_score != null) podcast.feedback.topic_score = Math.max(1, Math.min(10, data.topic_score));
      if (data.host_score != null) podcast.feedback.host_score = Math.max(1, Math.min(10, data.host_score));
      if (data.sentiment === 'positive') podcast.feedback.quick_likes = (podcast.feedback.quick_likes || 0) + 1;
      if (data.sentiment === 'negative') podcast.feedback.quick_dislikes = (podcast.feedback.quick_dislikes || 0) + 1;
      if (data.why) podcast.feedback.why_i_like.push(data.why);
      podcast.feedback.episodes_rated = (podcast.feedback.episodes_rated || 0) + 1;
      if (data.weight_delta) {
        podcast.priority = Math.max(1, Math.min(10, (podcast.priority || 5) + data.weight_delta));
      }
    }
  }
  if (action === 'add_channel' && data?.name) {
    const exists = profile.known_podcasts.find(p => p.name === data.name);
    if (!exists) {
      profile.known_podcasts.push({
        name: data.name,
        rss_url: data.rss_url || null,
        youtube_rss_url: data.youtube_rss_url || null,
        language: data.language || 'es',
        priority: 6,
        max_duration_minutes: 90,
        feedback: {topic_score: null, host_score: null, completion_rate: null, why_i_like: [], episodes_rated: 0, quick_likes: 0, quick_dislikes: 0}
      });
    }
  }
  profile.profile_update_count = (profile.profile_update_count || 0) + 1;
  profile.last_updated = new Date().toISOString();
  fs.writeFileSync(profilePath, JSON.stringify(profile, null, 2));
  // Store in ratings history if proactive report
  if (profileUpdate.store_in_ratings_history) {
    const ratingsPath = '/data/ratings_history.json';
    const ratings = JSON.parse(fs.readFileSync(ratingsPath, 'utf8'));
    ratings.proactive_reports.push({
      ...profileUpdate,
      timestamp: new Date().toISOString()
    });
    fs.writeFileSync(ratingsPath, JSON.stringify(ratings, null, 2));
  }
}
return [{json: {reply_text: replyText}}];

const fs = require('fs');
const inp = $input.first().json;
const queuePath = '/data/podcast_queue.json';

let queue = {items: []};
try { queue = JSON.parse(fs.readFileSync(queuePath, 'utf8')); } catch(e) {}
const saveQueue = () => fs.writeFileSync(queuePath, JSON.stringify(queue, null, 2));

// Normalize action from either path
const action = inp.queue_action || inp.action || 'list';
const itemId  = inp.item_id || '';
const cbId    = inp.callback_query_id || null;

// LIST — one message per episode so buttons appear next to each title
if (action === 'list') {
  const pending = queue.items.filter(i => i.status === 'pending');
  if (!pending.length) {
    return [{json: {reply_text: '📋 *Tu lista de escucha está vacía*\n\nUsa 📋 en el digest para añadir episodios, o escríbeme\n`/add Nombre del episodio`', reply_markup: null, callback_query_id: cbId, answer_text: null}}];
  }
  const epNumRe = /\bEp\.?\s*(\d+)\b|\b#(\d+)\b|\bEpisode\s+(\d+)\b|\bCap\.?\s*(\d+)\b/i;
  const result = [];
  const slice = pending.slice(0, 8);
  slice.forEach((item, i) => {
    const dur = item.duration_min ? ` · ${item.duration_min}min` : '';
    const m = item.title.match(epNumRe);
    const epTag = m ? ` · #${m[1]||m[2]||m[3]||m[4]}` : '';
    const header = i === 0 ? `📋 *Lista de escucha* (${pending.length} pendiente${pending.length!==1?'s':''})\n\n` : '';
    const text = `${header}*${i+1}.* *${item.title}*${epTag}\n_${item.podcast || 'Podcast'}${dur}_`;
    const row = [
      {text: '✅ Escuchado', callback_data: `q_done:${item.id}`},
      {text: '⏭ Saltar',    callback_data: `q_skip:${item.id}`},
      {text: '🗑',           callback_data: `q_del:${item.id}`}
    ];
    if (item.url) row.push({text: '🔗', url: item.url});
    result.push({json: {reply_text: text, reply_markup: JSON.stringify({inline_keyboard: [row]}), callback_query_id: cbId, answer_text: null}});
  });
  if (pending.length > 8) result.push({json: {reply_text: `_...y ${pending.length - 8} episodios más_`, reply_markup: null, callback_query_id: cbId, answer_text: null}});
  return result;
}

// ADD (from /add command or from 📋 digest button)
if (action === 'add' || action === 'q_add') {
  // From digest button: inp has item data stored in digest
  let title = inp.queue_title || inp.text || 'Sin título';
  let podcast = inp.queue_podcast || '';
  let url = inp.queue_url || '';
  let duration = inp.queue_duration || null;
  let source = inp.queue_source || 'manual';

  // Try to find item data from last_digest if coming from q_add callback
  if (action === 'q_add' && itemId) {
    try {
      const digest = JSON.parse(fs.readFileSync('/data/last_digest.json', 'utf8'));
      const found = (digest.items || []).find(i => i.id === itemId || i.id.startsWith(itemId));
      if (found) { title = found.title; podcast = found.feed_name || ''; url = found.url || ''; duration = found.duration_minutes || null; source = 'digest'; }
    } catch(e) {}
    // Fallback: check V4 daily tracker episodes cache
    if (title === 'Sin t\u00edtulo' || !title) {
      try {
        const v4Cache = JSON.parse(fs.readFileSync('/data/v4_episodes_cache.json', 'utf8'));
        const found = v4Cache[itemId];
        if (found) { title = found.title; podcast = found.podcast; url = found.url; duration = found.duration_min; source = 'daily_tracker'; }
      } catch(e) {}
    }
    // Fallback: check episode browse cache (from /elegir, /desde commands)
    if (itemId.startsWith('eb') && (title === 'Sin t\u00edtulo' || !title)) {
      try {
        const browseCache = JSON.parse(fs.readFileSync('/data/episode_browse_cache.json', 'utf8'));
        const found = browseCache[itemId];
        if (found) { title = found.title; podcast = found.podcast; url = found.url; duration = found.duration_min; source = 'browse'; }
      } catch(e) {}
    }
  }

  // Avoid duplicates
  const exists = queue.items.find(i => i.title === title && i.status === 'pending');
  if (exists) {
    return [{json: {reply_text: `📋 *${title}* ya está en tu lista`, reply_markup: null, callback_query_id: cbId, answer_text: 'Ya en la lista'}}];
  }

  const newItem = {
    id: 'q' + Date.now().toString(36).slice(-8),
    title, podcast, url,
    duration_min: duration,
    source,
    added_at: new Date().toISOString(),
    status: 'pending',
    rating: null
  };
  queue.items.push(newItem);
  saveQueue();
  // Mark browse episode as seen so /elegir won't re-show it
  if (itemId && itemId.startsWith('eb')) {
    try {
      const cachePath = '/data/episode_browse_cache.json';
      const bc = JSON.parse(fs.readFileSync(cachePath, 'utf8'));
      if (!bc._seen) bc._seen = {};
      bc._seen[(podcast || '') + '||' + title] = 'added';
      fs.writeFileSync(cachePath, JSON.stringify(bc, null, 2));
    } catch(e) {}
  }
  return [{json: {reply_text: `📋 Añadido a tu lista: *${title}*`, reply_markup: null, callback_query_id: cbId, answer_text: '✅ Añadido'}}];
}

// DONE
if (action === 'q_done') {
  const item = queue.items.find(i => i.id === itemId);
  if (!item) return [{json: {reply_text: 'No encontrado', reply_markup: null, callback_query_id: cbId, answer_text: null}}];
  item.status = 'listened';
