    {text: '1⭐', callback_data: `q_rate:${itemId}:1`},
    {text: '2⭐', callback_data: `q_rate:${itemId}:2`},
    {text: '3⭐', callback_data: `q_rate:${itemId}:3`},
    {text: '4⭐', callback_data: `q_rate:${itemId}:4`},
    {text: '5⭐', callback_data: `q_rate:${itemId}:5`}
  ]]};
  return [{json: {reply_text: `✅ *${item.title}*\n\n¿Cuánto te ha gustado? (0–5)`, reply_markup: JSON.stringify(ratingMarkup), callback_query_id: cbId, answer_text: '¡Marcado!'}}];
}

// SKIP
if (action === 'q_skip') {
  const item = queue.items.find(i => i.id === itemId);
  if (item) { item.status = 'skipped'; saveQueue(); }
  return [{json: {reply_text: null, reply_markup: null, callback_query_id: cbId, answer_text: '⏭ Saltado'}}];
