const fs = require('fs');
const crypto = require('crypto');
const inp = $input.first().json;
const query = inp.search_query || '';
const cbId = inp.callback_query_id || null;
const cachePath = '/data/podcast_search_cache.json';

function httpGet(urlStr, reqHeaders = {}, redirects = 5) {
  return new Promise((resolve, reject) => {
    if (redirects < 0) return reject(new Error('too many redirects'));
    const https = require('https'), http = require('http');
    const lib = urlStr.startsWith('https') ? https : http;
    lib.get(urlStr, {headers: {'User-Agent': 'PodcastBot/1.0', ...reqHeaders}}, (res) => {
      if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
        res.resume();
        return resolve(httpGet(res.headers.location, reqHeaders, redirects - 1));
      }
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const body = Buffer.concat(chunks).toString();
        try { resolve(JSON.parse(body)); } catch(e) { resolve(body); }
      });
    }).on('error', reject).setTimeout(10000, function(){ this.destroy(new Error('timeout')); });
  });
}

// ── MULTI-FOLLOW: auto-pick top result for each name ──────────────────────────
if (inp.search_queries && inp.search_queries.length > 0) {
  const profilePath = '/data/user_profile.json';
  const profile = JSON.parse(fs.readFileSync(profilePath, 'utf8'));
  const podcasts = profile.known_podcasts || [];
  const added = [...(inp.pre_added || [])];
  const already = [...(inp.already_following || [])];
  const notFound = [];
  for (const q of inp.search_queries) {
    if (podcasts.find(p => p.name.toLowerCase() === q.toLowerCase())) { already.push(q); continue; }
    let found = null;
    try {
      const d = await httpGet(`https://itunes.apple.com/search?term=${encodeURIComponent(q)}&media=podcast&limit=3`);
      if (d.results && d.results[0] && d.results[0].feedUrl) found = {name: d.results[0].collectionName, rss_url: d.results[0].feedUrl, youtube_rss_url: null};
    } catch(e) {}
    if (!found) {
      try {
        const epoch = Math.floor(Date.now()/1000);
        const apiKey = $env.PODCASTINDEX_API_KEY, apiSecret = $env.PODCASTINDEX_API_SECRET;
        const hash = crypto.createHash('sha1').update(apiKey + apiSecret + epoch).digest('hex');
        const d = await httpGet(`https://api.podcastindex.org/api/1.0/search/byterm?q=${encodeURIComponent(q)}&max=1`, {'X-Auth-Key': apiKey, 'X-Auth-Date': String(epoch), 'Authorization': hash});
        if (d.feeds && d.feeds[0]) found = {name: d.feeds[0].title, rss_url: d.feeds[0].url, youtube_rss_url: null};
      } catch(e) {}
    }
    if (found) {
      if (podcasts.find(p => p.rss_url === found.rss_url || p.name === found.name)) { already.push(found.name); }
      else {
        podcasts.push({name: found.name, rss_url: found.rss_url||null, youtube_rss_url: found.youtube_rss_url||null, language: 'es', priority: 6, max_duration_minutes: 90, feedback: {topic_score:null,host_score:null,completion_rate:null,why_i_like:[],episodes_rated:0,quick_likes:0,quick_dislikes:0}});
        added.push(found.name);
      }
    } else { notFound.push(q); }
  }
  profile.known_podcasts = podcasts;
  profile.last_updated = new Date().toISOString();
  fs.writeFileSync(profilePath, JSON.stringify(profile, null, 2));
  let text = '';
  if (added.length) text += `✅ *${added.length} añadidos:*\n${added.map(n => `• ${n}`).join('\n')}\n\n`;
  if (already.length) text += `ℹ️ Ya los seguías: ${already.join(', ')}\n\n`;
  if (notFound.length) text += `❌ No encontrados: ${notFound.join(', ')}\n_Prueba con /follow individualmente._`;
  return [{json: {reply_text: text.trim(), reply_markup: null, callback_query_id: cbId, answer_text: null}}];
}
// ─────────────────────────────────────────────────────────────────────────────

const candidates = [];
const seen = new Set();
function add(name, rss_url, yt_rss, yt_ch) {
  const k = rss_url || yt_rss || name;
  if (seen.has(k)) return;
  seen.add(k);
  candidates.push({id: 'pfc' + candidates.length, name, rss_url: rss_url||null, youtube_rss_url: yt_rss||null, youtube_channel_url: yt_ch||null});
}

// 1. iTunes
try {
  const d = await httpGet(`https://itunes.apple.com/search?term=${encodeURIComponent(query)}&media=podcast&limit=5`);
  for (const r of (d.results || [])) if (r.feedUrl && r.collectionName) add(r.collectionName, r.feedUrl, null, null);
} catch(e) {}

// 2. Podcast Index
try {
  const epoch = Math.floor(Date.now()/1000);
  const apiKey = $env.PODCASTINDEX_API_KEY, apiSecret = $env.PODCASTINDEX_API_SECRET;
  const hash = crypto.createHash('sha1').update(apiKey + apiSecret + epoch).digest('hex');
  const d = await httpGet(`https://api.podcastindex.org/api/1.0/search/byterm?q=${encodeURIComponent(query)}&max=5`,
    {'X-Auth-Key': apiKey, 'X-Auth-Date': String(epoch), 'Authorization': hash});
  for (const f of (d.feeds || [])) if (f.url && f.title) add(f.title, f.url, null, null);
} catch(e) {}

// 3. YouTube
try {
  const d = await httpGet(`https://www.googleapis.com/youtube/v3/search?part=snippet&type=channel&q=${encodeURIComponent(query)}&maxResults=3&key=${$env.YOUTUBE_API_KEY}`);
  for (const ch of (d.items || [])) {
    const cid = ch.id.channelId;
    add(ch.snippet.channelTitle, null, `https://www.youtube.com/feeds/videos.xml?channel_id=${cid}`, `https://www.youtube.com/channel/${cid}`);
  }
} catch(e) {}

if (!candidates.length) {
  return [{json: {reply_text: `🔍 No encontré *${query}* en iTunes, PodcastIndex ni YouTube.\n\nPrueba con variaciones del nombre o pásame la URL del RSS directamente:\n\`/follow https://url-del-rss.com/feed\``, reply_markup: null, callback_query_id: cbId, answer_text: 'No encontrado'}}];
}

const cache = {};
for (const c of candidates) cache[c.id] = c;
fs.writeFileSync(cachePath, JSON.stringify(cache, null, 2));

const rows = candidates.slice(0, 5).map(c => [{
  text: (c.rss_url ? '📡 ' : '📺 ') + c.name.slice(0, 35),
  callback_data: `pf_choose:${c.id}`
}]);
rows.push([{text: '❌ Ninguno de estos', callback_data: 'pf_none:x'}]);

return [{json: {
  reply_text: `🔍 *Resultados para "${query}"*\n\nElige el correcto:`,
  reply_markup: JSON.stringify({inline_keyboard: rows}),
  callback_query_id: cbId, answer_text: null
}}];

const fs = require('fs');
const inp = $input.first().json;
const {episodes_action, episode_count, podcast_filter, raw_text} = inp;
const cbId = inp.callback_query_id || null;
const profilePath = '/data/user_profile.json';
const queuePath = '/data/podcast_queue.json';
const cachePath = '/data/episode_browse_cache.json';

const profile = JSON.parse(fs.readFileSync(profilePath, 'utf8'));
let queue = {items: []};
try { queue = JSON.parse(fs.readFileSync(queuePath, 'utf8')); } catch(e) {}
let browseCache = {};
try { browseCache = JSON.parse(fs.readFileSync(cachePath, 'utf8')); } catch(e) {}

// Select podcasts
let podcasts = (profile.known_podcasts || []).filter(p => p.rss_url || p.youtube_rss_url);
if (podcast_filter && podcast_filter.trim()) {
  const q = podcast_filter.toLowerCase();
  podcasts = podcasts.filter(p => p.name.toLowerCase().includes(q));
}
if (!podcasts.length) {
  const msg = podcast_filter && podcast_filter.trim()
    ? `No encontré ningún podcast que coincida con "${podcast_filter}". Usa /podcasts para ver tu lista.`
    : 'No tienes podcasts con RSS o YouTube configurados. Añade uno con /follow.';
  return [{json: {reply_text: msg, reply_markup: null, callback_query_id: cbId, answer_text: null}}];
}

// Build skip_clips map by podcast name
const skipClipsMap = {};
for (const p of podcasts) { if (p.skip_clips) skipClipsMap[p.name] = true; }

const CLIP_RE = /\b(short|shorts|clip|clips|recorte|recortes|highlight|highlights|teaser|trailer|avance|snippet)\b|#shorts/i;
function isClip(podcastName, title, duration) {
  if (!skipClipsMap[podcastName]) return false;
  if (duration) {
    const parts = String(duration).split(':').map(Number);
    const secs = parts.length === 3 ? parts[0]*3600+parts[1]*60+parts[2] : parts.length === 2 ? parts[0]*60+parts[1] : parseInt(duration,10);
    if (secs > 0 && secs < 600) return true;
  }
  return CLIP_RE.test(title);
}

function parseDate(s) {
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return new Date(s + 'T00:00:00');
  const parts = s.split('/');
  const d = parts[0].padStart(2,'0'), m = parts[1].padStart(2,'0'), y = parts[2] || new Date().getFullYear();
  return new Date(`${y}-${m}-${d}T00:00:00`);
}

// Parse date range for browse_range
let dateFrom = null, dateTo = null;
if (episodes_action === 'browse_range') {
  const dateRe = /(\d{4}-\d{2}-\d{2}|\d{1,2}\/\d{1,2}(?:\/\d{4})?)/g;
  const rawStr = raw_text || '';
  const matches = [...rawStr.matchAll(dateRe)];
  if (matches[0]) dateFrom = parseDate(matches[0][1]);
  if (matches[1]) dateTo = parseDate(matches[1][1]);
  if (!dateTo || dateTo > new Date()) dateTo = new Date();
  if (!dateFrom) {
    return [{json: {reply_text: 'Formato de fecha no reconocido.\n\nUsa:\n`/desde 2026-04-01`\n`/desde 2026-04-01 hasta 2026-04-10`\n`/desde 01/04/2026 hasta 10/04/2026 Nombre Podcast`', reply_markup: null, callback_query_id: cbId, answer_text: null}}];
  }
}

// HTTP helper (fetch not available in n8n vm2 sandbox)
function httpGet(urlStr, redirects) {
  if (redirects === undefined) redirects = 5;
  return new Promise((resolve, reject) => {
    if (redirects < 0) return reject(new Error('too many redirects'));
    const https = require('https'), http = require('http');
    const lib = urlStr.startsWith('https') ? https : http;
    const req = lib.get(urlStr, {headers: {'User-Agent': 'PodcastBot/1.0'}}, (res) => {
      if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
        res.resume();
        return resolve(httpGet(res.headers.location, redirects - 1));
      }
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => resolve(Buffer.concat(chunks).toString()));
    });
    req.on('error', reject);
    req.setTimeout(10000, () => { req.destroy(new Error('timeout')); });
  });
}

// Fetch episodes from each podcast RSS/Atom feed
const allEpisodes = [];
for (const podcast of podcasts) {
  const feedUrl = podcast.rss_url || podcast.youtube_rss_url;
  try {
    const xml = await httpGet(feedUrl);
    // RSS: <item> tags
    const itemRe = /<item>([\s\S]*?)<\/item>/g;
    let m;
    while ((m = itemRe.exec(xml)) !== null) {
      const block = m[1];
      const get = (tag) => { const r = block.match(new RegExp('<' + tag + '[^>]*>(?:<!\\[CDATA\\[)?([\\s\\S]*?)(?:\\]\\]>)?<\\/' + tag + '>')); return r ? r[1].trim() : ''; };
      const encMatch = block.match(/enclosure[^>]+url="([^"]+)"/);
      const pubRaw = get('pubDate') || get('published') || get('dc:date');
      const d = pubRaw ? new Date(pubRaw) : null;
      const epTitle = get('title') || 'Sin título';
      const epDur = get('itunes:duration') || null;
      if (!isClip(podcast.name, epTitle, epDur)) allEpisodes.push({
        podcast_name: podcast.name,
        title: epTitle,
        url: get('link') || (encMatch ? encMatch[1] : ''),
        pub_date: d ? d.toISOString() : null,
        pub_date_obj: d,
        description: get('description').replace(/<[^>]+>/g, '').slice(0, 150),
        duration: epDur
      });
    }
    // Atom: <entry> tags (YouTube feeds)
    const entryRe = /<entry>([\s\S]*?)<\/entry>/g;
    while ((m = entryRe.exec(xml)) !== null) {
      const block = m[1];
      const getA = (tag) => { const r = block.match(new RegExp('<' + tag + '[^>]*>([\\s\\S]*?)<\\/' + tag + '>')); return r ? r[1].trim() : ''; };
      const linkM = block.match(/<link[^>]+href="([^"]+)"/);
      const pubRaw = getA('published') || getA('updated');
      const d = pubRaw ? new Date(pubRaw) : null;
      const atTitle = getA('title').replace(/<[^>]+>/g,'') || 'Sin título';
      if (!isClip(podcast.name, atTitle, null)) allEpisodes.push({
        podcast_name: podcast.name,
        title: atTitle,
        url: linkM ? linkM[1] : '',
        pub_date: d ? d.toISOString() : null,
        pub_date_obj: d,
        description: getA('summary').replace(/<[^>]+>/g, '').slice(0, 150),
        duration: null
      });
    }
  } catch(e) { /* skip failed feeds */ }
}

// Sort newest first
allEpisodes.sort((a, b) => (b.pub_date_obj || 0) - (a.pub_date_obj || 0));

// Apply filters
let filtered = allEpisodes;
if (episodes_action === 'browse_range') {
  filtered = allEpisodes.filter(ep => ep.pub_date_obj && ep.pub_date_obj >= dateFrom && ep.pub_date_obj <= dateTo);
}
// For browse/bulk_add: don't slice yet — slice AFTER seen filter so N means N new episodes

if (!filtered.length) {
  const msg = episodes_action === 'browse_range'
    ? 'No encontré episodios en ese rango de fechas.'
    : 'No encontré episodios en los feeds. ¿Tienes RSS configurado? Revisa con /podcasts.';
  return [{json: {reply_text: msg, reply_markup: null, callback_query_id: cbId, answer_text: null}}];
}

// BULK ADD
if (episodes_action === 'bulk_add') {
  // Apply count limit after seen filter
  const limit = episode_count || 5;
  filtered = filtered.filter(ep => !queuedTitles.has(ep.title)).slice(0, limit);
  const added = [];
  for (const ep of filtered) {
    const dup = queue.items.find(i => i.title === ep.title && i.status === 'pending');
    if (!dup) {
      queue.items.push({
        id: 'q' + Date.now().toString(36).slice(-8) + Math.random().toString(36).slice(-3),
        title: ep.title, podcast: ep.podcast_name, url: ep.url,
        duration_min: null, source: 'bulk_add',
        added_at: new Date().toISOString(), status: 'pending', rating: null
      });
      added.push(ep);
    }
  }
  fs.writeFileSync(queuePath, JSON.stringify(queue, null, 2));
  if (!added.length) return [{json: {reply_text: 'Todos los episodios ya estaban en tu lista.', reply_markup: null, callback_query_id: cbId, answer_text: null}}];
  let text = `✅ *${added.length} episodio${added.length > 1 ? 's' : ''} añadidos a tu lista*\n\n`;
  added.forEach((ep, i) => { text += `${i+1}. *${ep.podcast_name}* — ${ep.title}\n`; });
  return [{json: {reply_text: text, reply_markup: null, callback_query_id: cbId, answer_text: null}}];
}

// BROWSE / BROWSE_RANGE: one message per episode with ✅/❌ buttons
// Build sets of already-seen and queued episodes to avoid repeats
const seenKeys = new Set();
try {
  const bc = JSON.parse(fs.readFileSync(cachePath, 'utf8'));
  for (const [k] of Object.entries(bc._seen || {})) seenKeys.add(k);
} catch(e) {}
const queuedTitles = new Set((queue.items || []).filter(i => i.status === 'pending').map(i => i.title));

// Apply count limit AFTER seen filter so N means N unseen episodes
const browseLimit = episode_count || 5;
let browseCount = 0;

const result = [];
let counter = 0;
for (const ep of filtered) {
  if (browseCount >= browseLimit) break;
  const seenKey = (ep.podcast_name || '') + '||' + ep.title;
  if (seenKeys.has(seenKey) || queuedTitles.has(ep.title)) continue;
  browseCount++;
  const episode_id = 'eb' + Date.now().toString(36).slice(-6) + (counter++).toString(36);
  browseCache[episode_id] = {title: ep.title, podcast: ep.podcast_name, url: ep.url, duration_min: null, pub_date: ep.pub_date};
  const dateStr = ep.pub_date_obj ? ep.pub_date_obj.toLocaleDateString('es-ES', {day:'numeric', month:'short'}) : '';
  const dur = ep.duration ? ` · ${ep.duration}` : '';
  let text = `🎙️ *${ep.podcast_name}*\n_${ep.title}${dur}_`;
  if (dateStr) text += ` · ${dateStr}`;
