function formatPodcastList() {
  const podcasts = profile.known_podcasts || [];
  if (!podcasts.length) return {text: '🎤 *No sigues ningún podcast*\n\nUsa `/follow Nombre` para buscar uno.', markup: null};
  let text = `🎤 *Podcasts que sigues* (${podcasts.length})\n\n`;
  const rows = [];
  podcasts.forEach((p, i) => {
    const icons = (p.rss_url ? '📡' : '') + (p.youtube_rss_url ? '📺' : '');
    const clipIcon = p.skip_clips ? '🎧' : '✂️';
    text += `${i+1}. *${p.name}* ${icons}${p.skip_clips ? ' 🎧' : ''}\n`;
