const cachePath = '/data/episode_browse_cache.json';
const queuePath = '/data/podcast_queue.json';
const profilePath = '/data/user_profile.json';

function httpGet(urlStr, reqHeaders, redirects) {
  if (!reqHeaders) reqHeaders = {};
  if (redirects === undefined) redirects = 5;
  return new Promise((resolve, reject) => {
    if (redirects < 0) return reject(new Error('too many redirects'));
    const https = require('https'), http = require('http');
    const lib = urlStr.startsWith('https') ? https : http;
    const req = lib.get(urlStr, {headers: {'User-Agent': 'PodcastBot/1.0', ...reqHeaders}}, (res) => {
      if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
        res.resume();
        return resolve(httpGet(res.headers.location, reqHeaders, redirects - 1));
      }
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => { const b = Buffer.concat(chunks).toString(); try { resolve(JSON.parse(b)); } catch(e) { resolve(b); } });
    });
    req.on('error', reject);
    req.setTimeout(12000, () => { req.destroy(new Error('timeout')); });
  });
}

function httpPost(urlStr, headers, body) {
  return new Promise((resolve, reject) => {
    const https = require('https');
    const data = JSON.stringify(body);
    const url = new URL(urlStr);
    const req = https.request({hostname: url.hostname, path: url.pathname, method: 'POST', headers: {'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(data), ...headers}}, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => { const b = Buffer.concat(chunks).toString(); try { resolve(JSON.parse(b)); } catch(e) { resolve(b); } });
    });
    req.on('error', reject);
    req.setTimeout(30000, () => { req.destroy(new Error('timeout')); });
    req.write(data); req.end();
  });
}

const profile = JSON.parse(fs.readFileSync(profilePath, 'utf8'));
let queue = {items: []};
try { queue = JSON.parse(fs.readFileSync(queuePath, 'utf8')); } catch(e) {}
let browseCache = {};
try { browseCache = JSON.parse(fs.readFileSync(cachePath, 'utf8')); } catch(e) {}

const seenKeys = new Set();
for (const [k] of Object.entries(browseCache._seen || {})) seenKeys.add(k);
const queuedTitles = new Set((queue.items || []).filter(i => i.status === 'pending').map(i => i.title));
const skippedItems = (queue.items || []).filter(i => i.status === 'skipped').slice(-20);

const skipClipsMap = {};
for (const p of (profile.known_podcasts || [])) { if (p.skip_clips) skipClipsMap[p.name] = true; }
const CLIP_RE = /\b(short|shorts|clip|clips|recorte|recortes|highlight|highlights|teaser|trailer|avance|snippet)\b|#shorts/i;
function isClip(name, title, dur) {
  if (!skipClipsMap[name]) return false;
  if (dur) { const p = String(dur).split(':').map(Number); const s = p.length===3?p[0]*3600+p[1]*60+p[2]:p.length===2?p[0]*60+p[1]:parseInt(dur,10); if (s>0&&s<600) return true; }
  return CLIP_RE.test(title);
}

const cutoff = new Date();
cutoff.setDate(cutoff.getDate() - 30);
const allEpisodes = [];
const podcasts = (profile.known_podcasts || []).filter(p => p.rss_url || p.youtube_rss_url);

for (const podcast of podcasts) {
  const feedUrl = podcast.rss_url || podcast.youtube_rss_url;
  try {
    const xml = await httpGet(feedUrl);
    const itemRe = /<item>([\s\S]*?)<\/item>/g;
    let m;
    while ((m = itemRe.exec(xml)) !== null) {
      const block = m[1];
      const get = (tag) => { const r = block.match(new RegExp('<'+tag+'[^>]*>(?:<!\\[CDATA\\[)?([\\s\\S]*?)(?:\\]\\]>)?<\/'+tag+'>')); return r ? r[1].trim() : ''; };
      const encM = block.match(/enclosure[^>]+url="([^"]+)"/);
      const pubRaw = get('pubDate') || get('published');
      const d = pubRaw ? new Date(pubRaw) : null;
      if (!d || d < cutoff) continue;
      const title = get('title') || 'Sin título';
      const dur = get('itunes:duration') || null;
      if (isClip(podcast.name, title, dur)) continue;
      const sk = podcast.name + '||' + title;
      if (seenKeys.has(sk) || queuedTitles.has(title)) continue;
      allEpisodes.push({podcast_name: podcast.name, title, url: get('link')||(encM?encM[1]:''), pub_date: d.toISOString(), description: get('description').replace(/<[^>]+>/g,'').slice(0,200), duration: dur});
    }
    const entryRe = /<entry>([\s\S]*?)<\/entry>/g;
    while ((m = entryRe.exec(xml)) !== null) {
      const block = m[1];
      const getA = (tag) => { const r = block.match(new RegExp('<'+tag+'[^>]*>([\\s\\S]*?)<\/'+tag+'>')); return r ? r[1].trim() : ''; };
      const linkM = block.match(/<link[^>]+href="([^"]+)"/);
      const pubRaw = getA('published') || getA('updated');
      const d = pubRaw ? new Date(pubRaw) : null;
      if (!d || d < cutoff) continue;
      const title = getA('title').replace(/<[^>]+>/g,'') || 'Sin título';
      if (isClip(podcast.name, title, null)) continue;
      const sk = podcast.name + '||' + title;
      if (seenKeys.has(sk) || queuedTitles.has(title)) continue;
      allEpisodes.push({podcast_name: podcast.name, title, url: linkM?linkM[1]:'', pub_date: d.toISOString(), description: getA('summary').replace(/<[^>]+>/g,'').slice(0,200), duration: null});
    }
  } catch(e) {}
}

if (!allEpisodes.length) {
  return [{json: {reply_text: '😕 No encontré episodios nuevos para recomendar. Prueba en unos días o añade más podcasts con /follow.', reply_markup: null, callback_query_id: cbId, answer_text: null}}];
}

allEpisodes.sort((a, b) => new Date(b.pub_date) - new Date(a.pub_date));
const candidates = allEpisodes.slice(0, 40);

let ratingsStr = 'Sin valoraciones aún.';
try {
  const rh = JSON.parse(fs.readFileSync('/data/ratings_history.json', 'utf8'));
  const recent = (rh.ratings || []).slice(-10);
  if (recent.length) ratingsStr = recent.map(r => `- "${r.title}" → ${r.rating}★`).join('\n');
} catch(e) {}

const skippedStr = skippedItems.length
  ? skippedItems.map(i => `- "${i.title}" (${i.podcast || ''})`).join('\n')
  : 'Ninguno.';

const episodeList = candidates.map((ep, i) => {
  const d = new Date(ep.pub_date).toLocaleDateString('es-ES', {day:'numeric', month:'short'});
  return `${i+1}. [${ep.podcast_name}] "${ep.title}" (${d})${ep.description ? '\n   '+ep.description.slice(0,120) : ''}`;
