const prompt = `Eres un recomendador de podcasts. Selecciona exactamente ${count} episodios de la lista que más le gustarán al usuario según su historial.\n\nVALORACIONES RECIENTES (positivo = le gustó, negativo = no):\n${ratingsStr}\n\nEPISODIOS SALTADOS RECIENTEMENTE (no recomendar estos ni similares):\n${skippedStr}\n\nEPISODIOS DISPONIBLES:\n${episodeList}\n\nResponde SOLO con JSON válido, sin texto extra:\n[{"idx": 1, "reason": "frase corta máx 80 chars"}, ...]\n\nElige ${count} episodios distintos. Evita recomendar episodios similares a los saltados.`;

let picks = [];
try {
  const resp = await httpPost('https://api.anthropic.com/v1/messages', {'x-api-key': $env.ANTHROPIC_API_KEY, 'anthropic-version': '2023-06-01'}, {model: 'claude-sonnet-4-5', max_tokens: 600, messages: [{role: 'user', content: prompt}]});
  const text = resp.content?.[0]?.text || '';
  const jm = text.match(/\[[\s\S]*\]/);
  if (jm) picks = JSON.parse(jm[0]);
} catch(e) {
  return [{json: {reply_text: '❌ Error al generar recomendaciones. Inténtalo de nuevo.', reply_markup: null, callback_query_id: cbId, answer_text: null}}];
