  const d = new Date(ep.pub_date).toLocaleDateString('es-ES', {day:'numeric', month:'short'});
  const header = counter === 1 ? `🎯 *${count} recomendaciones para ti*\n\n` : '';
  const text = `${header}🎙 *${ep.podcast_name}*\n_${ep.title}_ · ${d}\n\n💡 ${pick.reason}${ep.url ? '\n🔗 '+ep.url : ''}`;
  result.push({json: {reply_text: text, reply_markup: JSON.stringify({inline_keyboard: [[{text: '✅ Añadir', callback_data: `q_add:${episode_id}`},{text: '❌ Saltar', callback_data: `eb_skip:${episode_id}`}]]}), callback_query_id: null, answer_text: null}});
}
fs.writeFileSync(cachePath, JSON.stringify(browseCache, null, 2));
