      const stars = i.rating != null ? ' · ' + '⭐'.repeat(i.rating || 0) + (i.rating === 0 ? '0⭐' : '') : '';
      const date = i.listened_at ? new Date(i.listened_at).toLocaleDateString('es-ES', {day:'numeric', month:'short'}) : '';
      return `• *${i.title}* ${i.podcast ? '_('+i.podcast+')_' : ''}${stars}${date ? ' · '+date : ''}`;
    }).join('\n')
  : '_Ninguno aún_';

// Reportes proactivos
const reports = (ratings.proactive_reports || []).slice(-5).reverse();
const reportLines = reports.length
  ? reports.map(r => {
      const s = r.data?.sentiment === 'positive' ? '👍' : r.data?.sentiment === 'negative' ? '👎' : '😐';
      const date = r.timestamp ? new Date(r.timestamp).toLocaleDateString('es-ES', {day:'numeric', month:'short'}) : '';
      return `${s} *${r.data?.name || '?'}*${date ? ' · '+date : ''}${r.report_summary ? '\n  _'+r.report_summary+'_' : ''}`;
    }).join('\n')
  : '_Ninguno aún_';

// Valoraciones rápidas recientes
const recentRatings = (ratings.ratings || []).slice(-5).reverse();
const ratingLines = recentRatings.length
  ? recentRatings.map(r => {
      const stars = r.rating != null ? '⭐'.repeat(r.rating) || '0⭐' : r.action === 'like' ? '👍' : '👎';
      return `${stars} _${r.title || r.item_id}_`;
    }).join('\n')
  : '_Ninguna aún_';

let msg = `👤 *Tu perfil de gustos*\n\n`;
msg += `📻 *Podcasts seguidos* (${podcasts.length})\n${podcastLines || '_Ninguno_'}\n`;
if (interestLines) msg += `\n🏷 *Temas de interés*\n${interestLines}\n`;
if (hostLines) msg += `\n🎙 *Presentadores favoritos*\n${hostLines}\n`;
msg += `\n✅ *Episodios escuchados recientemente* (últimos 10)\n${listenedLines}\n`;
msg += `\n💬 *Lo que me has contado* (últimos 5)\n${reportLines}\n`;
msg += `\n⭐ *Valoraciones recientes*\n${ratingLines}`;

// Telegram has 4096 char limit per message
if (msg.length > 4000) msg = msg.slice(0, 3990) + '\n_[truncado]_';

return [{json: {reply_text: msg, reply_markup: null, callback_query_id: null, answer_text: null}}];
